+fn flat_to_multi(flat: usize, strides: &[usize], _dims: &[u32]) -> Vec<usize> {
+    let mut multi = Vec::with_capacity(strides.len());
+    let mut remainder = flat;
+    for &stride in strides {
+        multi.push(remainder / stride);
+        remainder %= stride;
+    }
+    multi
+}
